import type { SelectionState } from '../../../../charts/core/components/annotations/types/state.js';
import type { MinMax } from '../../../../charts/core/types/min-max.js';
/**
 *
 * Extend the tanstack table's state for the Gantt chart.
 * @internal
 */
export interface DataTableGanttChartState {
    /**
     * Record of min/max values for gantt columns.
     */
    ganttMinMaxValues?: Record<string, MinMax>;
    /**
     * Current annotations selection state for each gantt column,
     * used for indicator rendering in cells based on header hover.
     */
    ganttAnnotationsSelection?: Record<string, Partial<SelectionState>>;
}
/**
 * Instance methods for the Gantt chart feature on the table.
 * @internal
 */
export interface DataTableGanttChartInstance {
    /**
     * Updates the annotations selection state for a specific gantt column.
     */
    setGanttAnnotationsSelection: (columnId: string, selection: Partial<SelectionState>) => void;
}
